def _parse_feat(cell):
    """Parse a cell that is already a plain number string (e.g. z-scored CSV)."""
    if cell is None:
        return None
    s = str(cell).strip()
    if s == "" or s.lower() == "nan":
        return None
    try:
        return float(s)
    except ValueError:
        return None


def _parse_raw_feature_cell(cell):
    """First numeric literal in cell, like ``normalize.extract_numeric_column``."""
    if cell is None:
        return None
    s = str(cell).strip()
    if s == "" or s.lower() == "nan":
        return None
    try:
        return float(s)
    except ValueError:
        pass
    m = re.search(r"([-+]?\d*\.?\d+)", s)
    if not m:
        return None
    return float(m.group(1))


def _cell_float_norm(value):
    """Missing normalized feature -> 0.0 (old behavior for ``raw_features=False``)."""
    v = _parse_feat(value)
    return 0.0 if v is None else v


def _zscored_query(row, raw_features):
    if raw_features:
        z = []
        for j, key in enumerate(FEATURE_COLS):
            x = _parse_raw_feature_cell(row.get(key))
            if x is None:
                x = _FEATURE_MEANS[j]
            mu = _FEATURE_MEANS[j]
            sig = _FEATURE_STDS[j]
            if sig == 0:
                z.append(0.0)
            else:
                z.append((float(x) - mu) / sig)
        return tuple(z)
    return tuple(_cell_float_norm(row.get(key)) for key in FEATURE_COLS)


def _dist2_7(a, b):
    s = 0.0
    for j in range(7):
        d = a[j] - b[j]
        s += d * d
    return s


def _majority_vote(neighbor_labels):
    counts = Counter(neighbor_labels)
    top = max(counts.values())
    tied = [lab for lab, c in counts.items() if c == top]
    return min(tied, key=lambda lab: _CLASS_ORDER.index(lab))


def predict(row, raw_features=True):
    """One row: dict-like keyed by CSV headers (e.g. DictReader).

    ``raw_features=True`` (default): cells are raw survey values; z-score using
    training means/stds. ``False``: cells are already z-scores (e.g. *_norm.csv).
    """
    q = _zscored_query(row, raw_features)
    dists = []
    for i, (tx, lab) in enumerate(_TRAIN):
        d2 = _dist2_7(q, tx)
        dists.append((d2, i, lab))
    dists.sort(key=lambda t: (t[0], t[1]))
    vlabels = [lab for _, _, lab in dists[:K]]
    return _majority_vote(vlabels)


def predict_all(filename, raw_features=True):
    with open(filename, newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        rows = list(reader)
    return [predict(row, raw_features=raw_features) for row in rows]
